#include <stdio.h>
int min(int a,int b){
    return a>b?b:a;
}
int max(int a,int b){
    return a<b?b:a;
}

int main()
{
    int b,r,mi,ma;


    scanf("%d",&b);
    scanf("%d",&r);
        mi=min(b,r);
        ma=max(b,r);
    printf("%d %d",mi,(ma-mi)/2);


    return 0;
}

