fn main() {
    let mut input = String::new();
    std::io::stdin().read_line(&mut input).expect("INPUT::read line failed");

    let mut input = input.trim().split(' ');
    let mut shoes = [i32::default();2];
    shoes[0] = input.next().unwrap().parse::<i32>().unwrap();
    shoes[1] = input.next().unwrap().parse::<i32>().unwrap();

    if shoes[0] > shoes[1] {
        shoes.swap(0, 1);
    }

    let fashion = shoes[0];
    let normal = (shoes[1] - fashion) / 2;

    println!("{} {}", fashion, normal);


}
